REPLACE INTO `mbti_test_results` VALUES (95, 6, 'face', '{\"pdp\": {\"primary\": \"猫头鹰\", \"secondary\": \"\"}, \"disc\": {\"primary\": \"C\", \"secondary\": \"\"}, \"mbti\": {\"type\": \"INTJ\", \"title\": \"战略家\"}, \"overview\": \"理性稳健，善于规划与分析，做事有节奏，抗压与持续力强，适合深度思考与系统搭建型工作。\", \"photoUrls\": [\"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260310/img_69afc606dde213.19573884.jpg\", \"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260310/img_69afc606a57237.43033150.jpg\", \"https://karuosiyujzk.oss-cn-shenzhen.aliyuncs.com/mbti/20260310/img_69afc606bdb774.70305849.jpg\"], \"boneAnalysis\": \"额区骨势平正，中上停过渡顺畅，骨肉均衡偏稳健型，属土金气质，重视现实与长期稳步推进。\", \"faceAnalysis\": \"额头饱满略宽，眼神沉稳有聚焦力，眉眼距离适中，整体给人理性内敛、思路清晰的印象。\", \"personalitySummary\": \"性格内敛理智，重视逻辑与结构，做事有计划感与原则边界，偏结果导向，不喜情绪化，人际上选择性投入，信任后稳定可靠。\"}', NULL, NULL, 0, 0, NULL, NULL, 1773127193, 1773127193, NULL, 'personal');
